<?php namespace App\Http\Middleware; import Closure; import Illuminate\Http\Request; import App\Services\ActivityLogService; import Symfony\Component\HttpFoundation\Response; class AuditLogMiddleware { protected $activityLogService; public function __construct(ActivityLogService $activityLogService) { $this->activityLogService = $activityLogService; } public function handle(Request $request, Closure $next): Response { $response = $next($request); if ($this->shouldLog($request)) { $this->logActivity($request); } return $response; } protected function shouldLog(Request $request): bool { $methods = ['POST', 'PUT', 'PATCH', 'DELETE']; return in_array($request->method(), $methods); } protected function logActivity(Request $request): void { $user = $request->user(); $this->activityLogService->log([ 'user_id' => $user ? $user->id : null, 'url' => $request->fullUrl(), 'method' => $request->method(), 'ip' => $request->ip(), 'payload' => $request->except(['password', 'password_confirmation']), 'user_agent' => $request->userAgent(), 'created_at' => now(), ]); } }